1	type Cell = [number, number]; // [x, y]
2	
3	const toKey = ([x, y]: Cell): string => `${x},${y}`;
4	const fromKey = (key: string): Cell => {
5	  const [x, y] = key.split(",").map(Number);
6	  return [x, y];
7	};
8	
9	const NEIGHBOR_OFFSETS: Cell[] = [
10	  [-1, -1], [0, -1], [1, -1],
11	  [-1, 0], [1, 0],
12	  [-1, 1], [0, 1], [1, 1],
13	];
14	
15	const isAliveNextGeneration = (alive: boolean, neighbors: number): boolean =>
16	  neighbors === 3 || (alive && neighbors === 2);
17	
18	export function nextGeneration(cells: Cell[]): Cell[] {
19	  const living = new Set(cells.map(toKey));
20	
21	  const neighborCounts = new Map<string, number>();
22	  for (const [x, y] of cells) {
23	    for (const [dx, dy] of NEIGHBOR_OFFSETS) {
24	      const key = toKey([x + dx, y + dy]);
25	      neighborCounts.set(key, (neighborCounts.get(key) ?? 0) + 1);
26	    }
27	  }
28	
29	  const nextCells: Cell[] = [];
30	  for (const [key, count] of neighborCounts) {
31	    if (isAliveNextGeneration(living.has(key), count)) {
32	      nextCells.push(fromKey(key));
33	    }
34	  }
35	  return nextCells;
36	}
37

